config.script:
let resp_len = body_4_1.body.len();
let status = body_4_1.status;
let is_ok = status >= 200 && status < 400;
#{site: __item.name, url: __item.url, status: status, is_ok: is_ok, body_length: resp_len}

let results = step_4.results;
let total = results.len();
let ok_count = 0;
let fail_count = 0;
let alert_sites = [];
for r in results {
    if r.is_ok { ok_count += 1; } else { fail_count += 1; alert_sites.push(r.site); }
}
let health_pct = ok_count * 100 / total;
let status = if fail_count > 0 { "🔴异常" } else { "🟢全通" };
let summary = [];
for r in results {
    summary.push(r.site + ":" + (if r.is_ok { "OK" } else { "FAIL" }));
}

// 趋势对比：读取上次持久化状态
let prev_health = 100.0;
let prev_status = "首次运行";
let trend = "→首次";
if step_3 != () {
    if step_3.health != () { prev_health = step_3.health; }
    if step_3.status != () { prev_status = step_3.status; }
    if health_pct > prev_health { trend = "↑改善"; }
    else if health_pct < prev_health { trend = "↓恶化"; }
    else { trend = "→持平"; }
}
let alert_sites_str = alert_sites.join(", ");

#{alert_sites: alert_sites, alert_sites_str: alert_sites_str, fail_count: fail_count, health_pct: health_pct, ok_count: ok_count, status: status, summary: summary.join(", "), total: total, trend: trend, prev_health: prev_health, prev_status: prev_status}

config.body:
{{step_5.status}}
正常: {{step_5.ok_count}}/{{step_5.total}} | 异常: {{step_5.fail_count}}/{{step_5.total}}
健康度: {{step_5.health_pct}}%（趋势: {{step_5.trend}}）
异常站点: {{step_5.alert_sites_str}}
日志: {{params.work_dir}}/monitor-log.xlsx
